// Extraer datos del cliente y archivo
const body = $input.first().json;

// Datos del formulario
const nombre = body.nombre || 'Cliente';
const telefono = body.telefono || '';
const problema = body.problema || 'Consulta General';
const servicio = body.servicio || 'soporte';
const fechaSolicitada = body.fecha || null;

// Imagen en base64 si existe
const imagenBase64 = body.imagen || null;
const tipoImagen = body.tipo_imagen || 'image/jpeg';

// Generar ID único
const id = Date.now().toString();

return {
  json: {
    id,
    nombre,
    telefono,
    problema,
    servicio,
    fechaSolicitada,
    imagenBase64,
    tipoImagen,
    contactoWA: telefono.replace(/\D/g, ''),
    timestamp: new Date().toISOString()
  }
};

// Procesar respuesta de IA y extraer información
const input = $input.first().json;
let diagnostico = '';
let urgencia = 'media';
let servicio = $input.item.json.servicio || 'soporte';
let duracion = 30;

try {
  if (input.candidates && input.candidates[0]?.content?.parts[0]?.text) {
    const texto = input.candidates[0].content.parts[0].text;
    diagnostico = texto;

    // Extraer urgencia
    if (texto.includes('urgencia')) {
      if (texto.toLowerCase().includes('alta')) urgencia = 'alta';
      else if (texto.toLowerCase().includes('baja')) urgencia = 'baja';
    }

    // Extraer servicio recomendado
    if (texto.toLowerCase().includes('cyber')) servicio = 'cyber';
    else if (texto.toLowerCase().includes('infra')) servicio = 'infra';
    else if (texto.toLowerCase().includes('ia') || texto.toLowerCase().includes('automatiz')) servicio = 'ia';
    else servicio = 'soporte';

    // Extraer duración
    const durMatch = texto.match(/(\d+)\s*(min|hora)/i);
    if (durMatch) {
      duracion = durMatch[2].toLowerCase().includes('hora') ? parseInt(durMatch[1]) * 60 : parseInt(durMatch[1]);
    }
  }
} catch (e) {
  diagnostico = 'Análisis en proceso. Contacte a Sistemas 4A.';
}

// Combinar con datos originales
const original = $('Recibir Datos').first().json;

return {
  json: {
    ...original,
    diagnostico,
    urgencia,
    servicio,
    duracion,
    requiereVisita: urgencia === 'alta'
  }
};

// Sugerir el mejor horario basado en urgencia y disponibilidad
const data = $input.first().json;

let fechaSugerida;
const fechaInput = data.fechaSolicitada;

if (fechaInput && new Date(fechaInput) > new Date()) {
  fechaSugerida = new Date(fechaInput);
} else {
  // Si no hay fecha o está en pasado, sugerir próximo disponible
  fechaSugerida = new Date();
  fechaSugerida.setHours(fechaSugerida.getHours() + 2);
  if (fechaSugerida.getHours() >= 18) {
    fechaSugerida.setDate(fechaSugerida.getDate() + 1);
    fechaSugerida.setHours(9, 0, 0, 0);
  }
}

const duracionMs = (data.duracion || 30) * 60 * 1000;
const fechaFin = new Date(fechaSugerida.getTime() + duracionMs);

// Mensaje según urgencia
let prioridadMsg = '';
switch(data.urgencia) {
  case 'alta': prioridadMsg = '🔴 URGENTE - Requiere atención inmediata'; break;
  case 'media': prioridadMsg = '🟡 Prioridad normal'; break;
  case 'baja': prioridadMsg = '🟢 Programación flexible'; break;
}

return {
  json: {
    ...data,
    fechaInicio: fechaSugerida.toISOString(),
    fechaFin: fechaFin.toISOString(),
    prioridadMsg,
    tituloEvento: `${data.servicio.toUpperCase()} - ${data.nombre}`
  }
};

